// Retrofit Client
private Retrofit createRetrofitClient() {
    OkHttpClient client = new OkHttpClient.Builder().build();
    return new Retrofit.Builder()
            .baseUrl(BuildConfig.BASE_URL)
            .client(client)
            .addConverterFactory(GsonConverterFactory.create())
            .build();
}

